  # Helper to build a richer location phrase by following location/isPartOf/country chains
          def build_location_phrase(loc_obj: str) -> str:
              loc = clean_obj(loc_obj)
              # If the location itself appears as a subject elsewhere, try to enrich it
              if loc in subject_groups:
                  extra = []
                  for rel in ("location", "isPartOf", "country"):
                      for t in subject_groups[loc]:
                          if t.predicate == rel:
                              extra.append(clean_obj(t.object))
                  if extra:
                      return f"{loc}, " + ", ".join(extra)
              return loc

          order = ["location", "height", "architect", "completionDate"]
          for pred in order:
              if pred in handled or pred not in pred_objs:
                  continue
              # Special handling for location to include chained information
              if pred == "location":
                  phrase = build_location_phrase(pred_objs[pred][0])
                  clause = f"is located in {phrase}"
              else:
                  verb = verb_map.get(pred, "has")
                  # Skip architect clause if the architect person has already been handled in a com...
                  if pred == "architect" and clean_obj(pred_objs[pred][0]) in persons_handled:
                      continue
                  clause = f"{verb} {clean_obj(pred_objs[pred][0])}"
              parts.append(clause)
              handled.add(pred)
